section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/testing-django-pytest.json",
  "type": "object",
  "required": [
    "uses_pytest_style",
    "uses_factory_boy",
    "uses_parametrize",
    "shallow_mocks_ok",
    "human_in_loop"
  ],
  "properties": {
    "uses_pytest_style": {
      "type": "boolean",
      "const": true
    },
    "uses_factory_boy": {
      "type": "boolean",
      "const": true
    },
    "uses_parametrize": {
      "type": "boolean",
      "const": true
    },
    "shallow_mocks_ok": {
      "type": "boolean",
      "const": true
    },
    "human_in_loop": {
      "type": "boolean",
      "const": true
    },
    "mutation_tested": {
      "type": "boolean"
    },
    "test_count": {
      "type": "integer",
      "minimum": 1
    }
  },
  "additionalProperties": false
}
